{
  "Cargo.toml": "[package]
name = "atomic-replacement"
version = "0.1.0"
edition = "2021"

[dependencies]
# We use the "std" feature here so `cargo run` works on your computer.
# Inside your actual embedded project, you likely use the "restore-state-u8" 
# or target-specific feature depending on your HAL.
critical-section = { version = "1.1", features = ["std"] }",
  "main.rs": "use core::sync::atomic::{AtomicUsize, Ordering};

struct Driver {
    // On thumbv6m, AtomicUsize load/store are native instructions, 
    // but fetch_add (Read-Modify-Write) is not hardware supported.
    // That is why you need the critical section.
    channel_index: AtomicUsize,
}

impl Driver {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// This function replicates `fetch_add(1, Ordering::Relaxed)`
    /// on architecture lacking atomic RMW instructions (like Cortex-M0+)
    fn get_next_index(&self) -> usize {
        // CRITICAL SECTION EXPLANATION:
        // 1. Why Critical Section? 
        //    It ensures exclusive access to the variable. On an RP2040 (multicore),
        //    implementation of critical_section ensures other cores or interrupts
        //    cannot interrupt the sequence between load and store.
        //
        // 2. Why Ordering::Relaxed?
        //    The memory barriers required to make the change visible to other cores/interrupts
        //    are provided by the mechanism entering/leaving the critical section
        //    (e.g., acquiring a spinlock or disabling interrupts).
        //    Therefore, inside the protected scope, Relaxed operations are sufficient
        //    because the critical section guarantees that no other thread is race-conditioning
        //    the value between the load and the store.
        critical_section::with(|_cs| {
            // 1. LOAD current value
            let old_val = self.channel_index.load(Ordering::Relaxed);

            // 2. MODIFY (mimic fetch_add wrapping behavior)
            let new_val = old_val.wrapping_add(1);

            // 3. STORE new value
            self.channel_index.store(new_val, Ordering::Relaxed);

            // 4. Return the old value (fetch_add returns previous value)
            old_val
        })
    }
}

fn main() {
    // This mimics the usage logic. 
    // In a real RP2040 setting, this would be inside your main loop or interrupt handler.

    let driver = Driver::new();

    println!("Simulating 5 atomic fetches...");

    for _ in 0..5 {
        let idx = driver.get_next_index();
        println!("Got index: {}", idx);
    }

    // Verify the internal state
    // Note: We can use Relaxed here because we are in the same thread 
    // just for verification, but technically reading shared state outside 
    // a CS without barriers relies on previous synchronization.
    let final_val = driver.channel_index.load(Ordering::Relaxed);
    println!("Final internal state: {}", final_val);

    assert_eq!(final_val, 5);
}"
}
```

