{
  "Cargo.toml": "[package]
name = "tracing-reload-example"
version = "0.1.0"
edition = "2021"

[dependencies]
tracing = "0.1"
tracing-subscriber = { version = "0.3", features = ["std", "fmt", "reload", "registry", "ansi"] }
",
  "main.rs": "use std::fs::File;
use tracing::{debug, error, info, warn};
use tracing_subscriber::{filter::LevelFilter, fmt, prelude::*, reload, Registry};

fn main() {
    // 1. Prepare the Log File
    let file = File::create("logfile.log").expect("Unable to create log file");

    // 2. Define the Console Layer
    // We start with a standard fmt layer
    let fmt_console = fmt::layer()
        .compact()
        .with_ansi(true);

    // We wrap the console layer with a filter (creating a Filtered layer)
    let filtered_console = fmt_console.with_filter(LevelFilter::INFO);

    // We wrap the Filtered layer in a Reload layer.
    // This allows us to modify the inner `Filtered` struct later.
    let (reloadable_console_layer, console_reload_handle) = reload::Layer::new(filtered_console);

    // 3. Define the File Layer (Static)
    // For demonstration, we keep this static to show that we are only changing the console.
    let file_layer = fmt::layer()
        .with_ansi(false)
        .with_writer(file)
        .with_filter(LevelFilter::WARN);

    // 4. Initialize the Registry
    // We add both layers. Providing strict types isn't necessary here thanks to `with`.
    let subscriber = Registry::default()
        .with(reloadable_console_layer)
        .with(file_layer);

    tracing::subscriber::set_global_default(subscriber).expect("Failed to set global subscriber");

    // --- Demonstration ---

    println!("\n--- Phase 1: Default Level (INFO) ---");
    info!("Console: Visible | File: Hidden (File is WARN+)");
    debug!("Console: Hidden  | File: Hidden");
    warn!("Console: Visible | File: Visible");

    println!("\n--- Phase 2: Changing Console to DEBUG ---");

    // Use the reload handle to modify the filter.
    // The closure receives the internal `Filtered<...>` struct.
    // We access mutable filter via `.filter_mut()` and assign a new LevelFilter.
    console_reload_handle.modify(|layer| *layer.filter_mut() = LevelFilter::DEBUG).unwrap();

    info!("Console: Visible | File: Hidden");
    debug!("Console: Visible | File: Hidden (File is still fixed at WARN)");

    println!("\n--- Phase 3: Changing Console to ERROR ---");

    console_reload_handle.modify(|layer| *layer.filter_mut() = LevelFilter::ERROR).unwrap();

    warn!("Console: Hidden  | File: Visible");
    error!("Console: Visible | File: Visible");

    println!("\nDone. Check logfile.log to confirm file levels never changed.");
}"
}
```

