fn main() -> PolarsResult<()> {
    // 1. Create a sample DataFrame with one string column
    let df = df!(
        "col1" => &["foo", "bar"]
    )?;

    // 2. Define the mapping logic
    // We map over the string column and return a List of Structs for each row.
