                                    &[s_c1, s_c2]
                                ).expect("Fields must have same length");

                                // Convert the StructChunked to a Series to be an item in the ListChunked
                                Some(struct_ca.into_series())
                            }
                            None => None,
                        }
                    })
                    .collect();

                // Return the new ListChunked as a Column
                Ok(Some(list_out.into_column()))
            },
            // 3. Define the output schema explicitly
            // We are changing String -> List(Struct(c1: String, c2: String))
