        // We capture a slice of the whole vector to access 'other' elements.
        let all_elems = &self.elems;

        all_elems.par_iter().enumerate().for_each(|(i, elem_i)| {
            // Q2 Optimization: Only iterate j > i.
            // If dist(i, j) < cutoff, we update BOTH i and j.
