struct DragManager {
    // We store the Signal of the child component directly.
    // This allows us to update the child without rebuilding the parent or iterating lists.
    active_target: Signal<Option<Signal<Coords>>>,

    // The offset prevents the element from "snapping" to its center when grabbed.
    drag_offset: Signal<Coords>,
}

impl DragManager {
    fn new() -> Self {
        Self {
            active_target: Signal::new(None),
            drag_offset: Signal::new(Coords::default()),
        }
