The solution to this problem is understanding that `sqlx::Decode` is intended for decoding a *single specific column type* (like parsing a JSON column into a struct or a custom Enum), whereas `sqlx::FromRow` is intended for mapping a *row of multiple columns* into a struct.

Since `Team` data exists in the database as separate columns (joined from the `teams` table), you need to query the data using a SQL `JOIN`, and then implement `FromRow` manually for `Employee` to tell SQLx how to map those joined columns (which alias `team_id`, `team_name`, etc.) into the nested `Team` struct.

Here is the complete, runnable solution. I have switched the types to `i64` to match SQLite's native integer type (which is signed), which is the idiomatic way to use SQLx with SQLite.

```json
{
  "Cargo.toml": "[package]
name = "sqlx_nested_example"
version = "0.1.0"
edition = "2021"

[dependencies]
# Using the same version as requested, with runtime-tokio and sqlite features
sqlx = { version = "0.8.6", features = ["runtime-tokio", "sqlite"] }
tokio = { version = "1.44.2", features = ["full"] }",
  "main.rs": "use sqlx::{sqlite::{SqlitePool, SqliteRow}, FromRow, Row, Executor};

// --- Struct Definitions ---

#[derive(Debug, PartialEq)]
pub struct Team {
    pub id: i64,
    pub name: String,
}

#[derive(Debug, PartialEq)]
pub struct Employee {
    pub id: i64,
    pub name: String,
    pub team: Team, // Nested struct
}

// --- The Solution: Manual FromRow Implementation ---

// We implement FromRow manually because standard `derive` cannot handle 
// nested structs that are spread across multiple flattened columns easily 
// without strict naming conventions or conflicts (both tables have 'id' and 'name').
//
// This allows us to map specific SQL aliases (team_id, team_name) to the nested struct.
impl<'r> FromRow<'r, SqliteRow> for Employee {
    fn from_row(row: &'r SqliteRow) -> Result<Self, sqlx::Error> {
        // We manually construct the nested Team struct by fetching specific 
        // column aliases that we will define in our SQL query.
        let team = Team {
            id: row.try_get("team_id")?,
            name: row.try_get("team_name")?,
        };

        Ok(Employee {
            id: row.try_get("id")?,
            name: row.try_get("name")?,
            team,
        })
    }
}

// --- Main Execution ---

#[tokio::main]
async fn main() -> Result<(), sqlx::Error> {
    // 1. Setup an in-memory database for this example
    let pool = SqlitePool::connect("sqlite::memory:").await?;

    // 2. Create Schema and Seed Data
    let setup_sql = "
        CREATE TABLE teams (
            id INTEGER PRIMARY KEY,
            name TEXT
        );

        CREATE TABLE employees (
            id INTEGER PRIMARY KEY,
            name TEXT,
            team_id INTEGER,
            FOREIGN KEY (team_id) REFERENCES teams(id)
        );

        INSERT INTO teams (id, name) VALUES (1, 'East Coast Team');
        INSERT INTO employees (id, name, team_id) VALUES (1, 'Boston Alice', 1);
    ";
    pool.execute(setup_sql).await?;

    println!("Database setup complete.");

    // 3. Fetch with JOIN
    // 
    // Key Takeaway: You cannot do `SELECT * FROM employees`. You must JOIN the teams
    // table and ALIAS the columns so they don't collide with employee columns.
    // Our custom `from_row` implementation above looks for 'team_id' and 'team_name'.
    let query = "
        SELECT 
            e.id, 
            e.name, 
            t.id as team_id, 
            t.name as team_name 
        FROM employees e
        JOIN teams t ON e.team_id = t.id
        WHERE e.id = 1
    ";

    let employee: Employee = sqlx::query_as(query)
        .fetch_one(&pool)
        .await?;

    // 4. Verify results
    println!("\nSuccessfully fetched Nested Employee:");
    println!("ID:   {}", employee.id);
    println!("Name: {}", employee.name);
    println!("Team: {} (ID: {})", employee.team.name, employee.team.id);

    assert_eq!(employee.name, "Boston Alice");
    assert_eq!(employee.team.name, "East Coast Team");

    Ok(())
}
"
}
