Here is a complete, self-contained solution. 

### concept
To achieve "lazy" loading where you don't read the whole container into memory, the idiomatic Bevy (0.12+) approach is to implement a custom **`AssetReader`**.

Standard `AssetLoader`s are designed to process a file *after* it has been fully read. An `AssetReader`, however, acts like a virtual file system. This allows you to treat a WAD file as a directory.

*   **Standard approach:** `assets/textures.wad` -> Loaded as one giant blob, decoded in memory.
*   **Lazy AssetReader approach:** `wad://textures.wad/skybox.png` -> The reader opens the real WAD file, seeks to the specific offset of the image, reads only those bytes, and passes them to the standard ImageLoader.

### Solution Features
1.  **`WadAssetReader`**: Intercepts paths starting with `wad://`. It parses the WAD header (lightweight), finds the offset of the requested file, and streams only that chunk.
2.  **Virtual Pathing**: Assets are accessed via `asset_server.load("wad://my_archive.wad/my_texture.tga")`.
3.  **Generator**: The `main` function automatically creates a dummy `.wad` file in `assets/` containing two distinct TGA images so you can verify it works immediately.

```json
{
  "Cargo.toml": "[package]
name = "lazy_wad_loader"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = { version = "0.14", default-features = true }
futures-lite = "2.3" # Needed for AsyncRead traits
thiserror = "1.0"",
  "main.rs": "use bevy::asset::io::{AssetReader, AssetReaderError, AssetSource, AssetSourceId, Reader};
use bevy::prelude::*;
use bevy::utils::BoxedFuture;
use futures_lite::io::Cursor;
use std::fs::File;
use std::io::{Read, Seek, SeekFrom, Write};
use std::path::Path;

// --------------------------------------------------------------------------------
// 1. Define the Custom Asset Reader
//    This acts as a bridge between Bevy's "files" and the data inside our WAD.
// --------------------------------------------------------------------------------

struct WadAssetReader;

impl AssetReader for WadAssetReader {
    // We treat the WAD file as the root for this source.
    // Request: "wad://my_files.wad/texture.tga"
    fn read<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Box<dyn Reader>, AssetReaderError>> {
        Box::pin(async move {
            // 1. Identify context strings
            // path comes in as "my_files.wad/texture.tga"
            let path_str = path.to_string_lossy();
            let parts: Vec<&str> = path_str.split(".wad/").collect();

            if parts.len() != 2 {
                return Err(AssetReaderError::NotFound(path.to_path_buf()));
            }

            let container_name = format!("{}.wad", parts[0]); // "my_files.wad"
            let entry_name = parts[1];                        // "texture.tga"

            // 2. Resolve physical path (in a real app, handle cross-platform paths properly)
            let container_path = Path::new("assets").join(&container_name);

            // 3. Open the container file (Blocking IO within async is simplified here for demo)
            //    In a production env, use async fs or spawn blocking tasks.
            let mut file = File::open(&container_path).map_err(|e| {
                 match e.kind() {
                     std::io::ErrorKind::NotFound => AssetReaderError::NotFound(container_path.clone()),
                     _ => AssetReaderError::Io(e.into())
                 }
            })?;

            // 4. PARSE WAD HEADER
            //    We scan the TOC to find the offset/size of `entry_name`.
            //    We do NOT load the heavy data here.
            let (offset, size) = find_entry_in_wad(&mut file, entry_name)
                .map_err(|_| AssetReaderError::NotFound(path.to_path_buf()))?;

            // 5. EXTRACT CHUNK
            //    Seek to the data location and read ONLY the needed bytes.
            file.seek(SeekFrom::Start(offset)).map_err(|e| AssetReaderError::Io(e.into()))?;
            let mut buffer = vec![0u8; size as usize];
            file.read_exact(&mut buffer).map_err(|e| AssetReaderError::Io(e.into()))?;

            println!("> Lazy Loaded '{}' from archive ({} bytes)", entry_name, size);

            // 6. Return a Reader (Cursor wraps the byte vec in an async reader interface)
            let reader: Box<dyn Reader> = Box::new(Cursor::new(buffer));
            Ok(reader)
        })
    }

    // Required boilerplate for directory listing (stubbed for this demo)
    fn read_meta<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<bevy::asset::io::AssetMeta, AssetReaderError>> {
        Box::pin(async move { Err(AssetReaderError::NotFound(path.to_path_buf())) })
    }

    fn read_directory<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<Box<dyn bevy::asset::io::PathStream>, AssetReaderError>> {
        Box::pin(async move { Err(AssetReaderError::NotFound(path.to_path_buf())) })
    }

    fn is_directory<'a>(&'a self, _path: &'a Path) -> BoxedFuture<'a, Result<bool, AssetReaderError>> {
        Box::pin(async move { Ok(false) })
    }
}

// --------------------------------------------------------------------------------
// 2. Minimal WAD Parser Logic (Helper)
// --------------------------------------------------------------------------------

/// Scans our Custom WAD format for a filename and returns (offset, size).
fn find_entry_in_wad(file: &mut File, target_name: &str) -> Result<(u64, u64), ()> {
    // --- FORMAT SPEC ---
    // Header: ["MYWAD" (5 bytes)] [FileCount (u32 LE)]
    // Entry:  [NameLen (u8)] [Name (Bytes)] [Offset (u64 LE)] [Size (u64 LE)]
    // Data:   [Binary Blob...]

    // Read Magic
    file.seek(SeekFrom::Start(0)).map_err(|_| ())?;
    let mut magic = [0u8; 5];
    file.read_exact(&mut magic).map_err(|_| ())?;
    if &magic != b"MYWAD" { return Err(()); }

    // Read Count
    let mut count_buf = [0u8; 4];
    file.read_exact(&mut count_buf).map_err(|_| ())?;
    let count = u32::from_le_bytes(count_buf);

    // Iterate Directory
    for _ in 0..count {
        // Read Name Len
        let mut name_len_buf = [0u8; 1];
        file.read_exact(&mut name_len_buf).map_err(|_| ())?;
        let name_len = name_len_buf[0] as usize;

        // Read Name
        let mut name_buf = vec![0u8; name_len];
        file.read_exact(&mut name_buf).map_err(|_| ())?;
        let name = String::from_utf8(name_buf).unwrap_or_default();

        // Read Offset & Size
        let mut meta_buf = [0u8; 16]; // 2x u64
        file.read_exact(&mut meta_buf).map_err(|_| ())?;
        let offset = u64::from_le_bytes(meta_buf[0..8].try_into().unwrap());
        let size = u64::from_le_bytes(meta_buf[8..16].try_into().unwrap());

        if name == target_name {
            return Ok((offset, size));
        }
    }

    Err(())
}

