        texture: asset_server.load("wad://data.wad/red_texture.tga"),
        transform: Transform::from_xyz(-100.0, 0.0, 0.0).with_scale(Vec3::splat(20.0)),
        ..default()
    });

    // Load Blue Texture from inside the WAD
    commands.spawn(SpriteBundle {
