fn create_dummy_wad_file() {
    let path = Path::new("assets/data.wad");
    if path.exists() { return; }
    std::fs::create_dir_all("assets").unwrap();

    let mut f = File::create(path).unwrap();

    println!("Generating dummy assets/data.wad for testing...");

    // Generate two valid minimal TGA images
    let red_tga = make_tga_bytes(255, 0, 0);
    let blue_tga = make_tga_bytes(0, 0, 255);

    // Calculate Layout
    // Offset starts after header. Header = 5 (magic) + 4 (count) + Entries.
    // Entry = 1(len) + NameLen + 16(u64+u64)

    let magic = b"MYWAD";
    let count: u32 = 2;

    let name1 = "red_texture.tga";
    let name2 = "blue_texture.tga";

    let header_size = 
          magic.len() + 4 
        + (1 + name1.len() + 16) 
        + (1 + name2.len() + 16);

    let offset1 = header_size as u64;
    let size1 = red_tga.len() as u64;
    let offset2 = offset1 + size1;
    let size2 = blue_tga.len() as u64;

    // Write Header
    f.write_all(magic).unwrap();
    f.write_all(&count.to_le_bytes()).unwrap();

    // Write Entry 1
    f.write_all(&[name1.len() as u8]).unwrap();
    f.write_all(name1.as_bytes()).unwrap();
    f.write_all(&offset1.to_le_bytes()).unwrap();
    f.write_all(&size1.to_le_bytes()).unwrap();

    // Write Entry 2
    f.write_all(&[name2.len() as u8]).unwrap();
    f.write_all(name2.as_bytes()).unwrap();
    f.write_all(&offset2.to_le_bytes()).unwrap();
    f.write_all(&size2.to_le_bytes()).unwrap();

    // Write Blobs
    f.write_all(&red_tga).unwrap();
    f.write_all(&blue_tga).unwrap();
}

fn make_tga_bytes(r: u8, g: u8, b: u8) -> Vec<u8> {
    let mut data = Vec::new();
    // TGA Header (Uncompressed RGB, 2x2 pixels)
    data.extend_from_slice(&[0,0,2,0,0,0,0,0,0,0,0,0,2,0,2,0,24,0]);
    // 4 Pixels (BGR format)
    for _ in 0..4 { data.extend_from_slice(&[b, g, r]); }
    data
}"
}
