/// Splits a string into tokens respecting single quotes, similar to a shell.
fn tokenize(s: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_quotes = false;
    // We track if a token has started to distinguish between multiple spaces (ignored)
    // and an empty quoted string "" (preserved).
    let mut token_started = false;

    for c in s.chars() {
        if in_quotes {
            if c == '\'' {
                in_quotes = false;
            } else {
                current_token.push(c);
            }
        } else {
            match c {
                '\'' => {
                    in_quotes = true;
                    token_started = true;
                }
                ' ' => {
                    if token_started {
                        // Finish the current token
                        tokens.push(mem::take(&mut current_token));
                        token_started = false;
                    }
                    // If token not started, this is just a consecutive space; ignore it.
                }
                _ => {
                    current_token.push(c);
                    token_started = true;
                }
            }
        }
    }

    // Push the final token if one was being built
    if token_started {
        tokens.push(current_token);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";

    // Expected output:
    // 3 args:
    // <one>
    // < two  three>
    // <four>

    let args = tokenize(input);

    println!("{} args:", args.len());
    for arg in args {
        println!("<{}>", arg);
    }
}
"
}
