    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("struct A with fields 'x' and 'b'")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        // Standard pattern: Option fields to handle order-independence
        let mut x = None;
        let mut b = None;

        // Note: We use `String` here instead of `&str`. 
