  "main.rs": "use std::borrow::Cow;
use std::marker::PhantomData;

// --- Mocks for the Trait/Types provided by the external crate ---

// A mock Meta struct to satisfy the `new` method requirements
#[derive(Debug, Default)]
pub struct Meta {
    pub name: Option<String>,
}

// The Resource trait as implied by the user's code
pub trait Resource {
    type DynamicType;

    fn meta(&self) -> Meta;

    // These signatures imply the Cow borrows from the DynamicType reference
    fn group(dt: &Self::DynamicType) -> Cow<'_, str>;
    fn kind(dt: &Self::DynamicType) -> Cow<'_, str>;
}

// --- The User's Structs and Implementation ---

#[derive(Debug, Clone)]
pub struct ResourceRef<'a, R: Resource>
where
    R::DynamicType: 'a + Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<Cow<'a, str>>,
    kind: Cow<'a, str>,
    name: String,
}

impl<R: Resource> ResourceRef<'_, R>
where
    R::DynamicType: 'static + Default,
{
    pub fn new(resource: R) -> Self {
        // Helper for the demo
        let name = resource
            .meta()
            .name
            .unwrap_or_else(|| "unnamed".to_string());
        Self::new_named(&name)
    }

    pub fn new_named(name: &str) -> Self {
        // 1. We create the owner of the data here.
        let dynamic_type = R::DynamicType::default();

        // 2. We get Cows that borrow from 'dynamic_type'.
        let group_ref = R::group(&dynamic_type);
        let kind_ref = R::kind(&dynamic_type);

        // THE FIX:
        // You cannot return a struct that owns 'dynamic_type' AND holds references (Cows) 
        // to 'dynamic_type' at the same time (Self-Referential Struct). 
        //
        // To fix this, you must break the link to the local variable reference.
        // We call `.into_owned()` followed by `Cow::Owned`. 
        // Note: If the trait returned a Borrowed static string, this might imply an allocation,
        // but it is legally required for safety unless you use unsafe constraints.

        let group = if group_ref.is_empty() {
            None
        } else {
            Some(Cow::Owned(group_ref.into_owned()))
        };

        let kind = Cow::Owned(kind_ref.into_owned());

        // Note: constructing with `Cow::Owned` satisfies 'a because an Owned Cow 
        // is valid for any lifetime 'a.

        Self {
            type_: PhantomData,
            dynamic_type,
            group,
            kind,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        self.kind.as_ref()
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

