// --- types ---

#[derive(Debug)]
pub struct Request {
    pub path: String,
}

#[derive(Debug)]
pub struct Response {
    pub body: String,
}

// The internal stored type. 
// We use Arc<Request> to simplify lifetimes (the efficient standard for async servers).
// If we used &Request, the returned Future would need to be bound by the request's lifetime,
// which adds significant complexity (HRTB) to the generic implementation.
type HandlerFn = Box<dyn Fn(Arc<Request>) -> BoxFuture<'static, Response> + Send + Sync + 'static>;

pub struct Handler(HandlerFn);

// --- traits & markers ---

// A trait to convert various function types into our unified `Handler` wrapper.
// The generic `M` is a "marker" type that helps the compiler distinguish 
// between the Sync and Async implementations, preventing the "conflicting implementations" error.
pub trait IntoHandler<M> {
    fn into_handler(self) -> Handler;
}

// Marker structs to distinguish implementation strategies
pub struct SyncMarker;
pub struct AsyncMarker;

// --- implementations ---

// 1. Implementation for Synchronous Functions
// Matches: fn(Arc<Request>) -> Response
impl<F> IntoHandler<SyncMarker> for F
where
    F: Fn(Arc<Request>) -> Response + Send + Sync + 'static,
{
    fn into_handler(self) -> Handler {
        // Wrap the sync calculation in a future automatically
        Handler(Box::new(move |req| {
            let res = self(req);
            Box::pin(futures::future::ready(res))
        }))
    }
}

// 2. Implementation for Asynchronous Functions
// Matches: fn(Arc<Request>) -> Future<Output = Response>
impl<F, Fut> IntoHandler<AsyncMarker> for F
where
    F: Fn(Arc<Request>) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send + 'static,
{
    fn into_handler(self) -> Handler {
        // Just box the returned future
        Handler(Box::new(move |req| {
            Box::pin(self(req))
        }))
    }
}

// --- server ---

pub struct Server {
    // In a real app, this would be a HashMap
    routes: Vec<(String, Handler)>,
}

impl Server {
    pub fn new() -> Self {
        Self { routes: Vec::new() }
    }

    // The generic entry point.
    // Rust infers `M` (SyncMarker or AsyncMarker) based on which trait impl matches `F`.
    pub fn add_route<F, M>(&mut self, path: &str, handler: F)
    where
        F: IntoHandler<M>,
    {
        self.routes.push((path.to_string(), handler.into_handler()));
    }

    // Simple runner to demonstrate it works
    pub async fn simulate_request(&self, path: &str) {
        println!("Server received request for: {}", path);

        // Find handler (simple linear search for demo)
        if let Some((_, handler)) = self.routes.iter().find(|(p, _)| p == path) {
            let req = Arc::new(Request { path: path.to_string() });
            // Call the handler
            let resp = (handler.0)(req).await;
            println!("  -> Response: {}", resp.body);
        } else {
            println!("  -> 404 Not Found");
        }
    }
}

