// A standard synchronous handler
fn sync_handler(req: Arc<Request>) -> Response {
    println!("  (Processing inside sync_handler)");
    Response {
        body: format!("Sync result for {}", req.path),
    }
}

// An asynchronous handler
async fn async_handler(req: Arc<Request>) -> Response {
    println!("  (Processing inside async_handler)");
    // Simulate async work
    tokio::time::sleep(std::time::Duration::from_millis(50)).await;
    Response {
        body: format!("Async result for {}", req.path),
    }
}

#[tokio::main]
async fn main() {
    let mut server = Server::new();

    // 1. Add a Sync route
