{
  "Cargo.toml": "[package]
name = "axum-validation-example"
version = "0.1.0"
edition = "2021"

[dependencies]
axum = { version = "0.7", features = ["macros"] }
tokio = { version = "1", features = ["full"] }
serde = { version = "1", features = ["derive"] }
serde_json = "1"
validator = { version = "0.19", features = ["derive"] }
tracing = "0.1"
tracing-subscriber = "0.3"

[dev-dependencies]
http-body-util = "0.1"
",
  "main.rs": "use axum::{
    async_trait,
    extract::{FromRef, FromRequest, FromRequestParts, Request, State, Json},
    http::{StatusCode, request::Parts, header::{HeaderName, HeaderValue}},
    response::{IntoResponse, Response},
    routing::post,
    Router,
};
use serde::{de::DeserializeOwned, Deserialize, Serialize};
use serde_json::json;
use std::sync::Arc;
use validator::Validate;

// ==========================================
// 1. DTOs and Validation Logic
// ==========================================

#[derive(Debug, Serialize, Deserialize, Validate)]
pub struct RevokeUser {
    // Fixed 'string' to 'String'
    #[validate(length(min = 6, message = "user_id must be at least 6 characters"))]
    pub user_id: String,
}

// ==========================================
// 2. Custom Extractor: ValidatedJson
// ==========================================

// Wrapper struct
#[derive(Debug, Clone, Copy, Default)]
pub struct ValidatedJson<T>(pub T);

// We must implement FromRequest to make it an Extractor.
#[async_trait]
impl<T, S> FromRequest<S> for ValidatedJson<T>
where
    T: DeserializeOwned + Validate,
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request(req: Request, state: &S) -> Result<Self, Self::Rejection> {
        // 1. Use Axum's built-in Json extractor to parse the body first
        let Json(value) = Json::<T>::from_request(req, state)
            .await
            .map_err(|err| APIError::JsonError(err.to_string()))?;

        // 2. Validate the parsed struct
        value.validate().map_err(|err| APIError::ValidationError(err.to_string()))?;

        // 3. Return wrapped successful value
        Ok(ValidatedJson(value))
    }
}

// ==========================================
// 3. Other Extractors (Headers, Auth, State)
// ==========================================

// Mock Shared State
#[derive(Clone)]
pub struct AppState {
    pub db_url: String,
}

// Mock API Version Header
pub struct ApiVersionHeader(pub String);

#[async_trait]
impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let header_name = HeaderName::from_static("x-api-version");
        let value = parts
            .headers
            .get(&header_name)
            .ok_or(APIError::MissingHeader("x-api-version".to_string()))?;

        let s = value.to_str().map_err(|_| APIError::InvalidHeader)?;
        Ok(ApiVersionHeader(s.to_string()))
    }
}

// Mock Access Claims
pub struct AccessClaims {
    pub sub: String,
    pub role: String,
}

impl AccessClaims {
    pub fn validate_role_admin(&self) -> Result<(), APIError> {
        if self.role != "admin" {
            return Err(APIError::Forbidden("Admin role required".to_string()));
        }
        Ok(())
    }
}

#[async_trait]
impl<S> FromRequestParts<S> for AccessClaims
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(_parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        // Mock decoding token. In reality, you'd check Authorization header here.
        Ok(AccessClaims {
            sub: "user_12345".to_string(),
            role: "admin".to_string(),
        })
    }
}

// ==========================================
// 4. Error Handling
// ==========================================

#[derive(Debug)]
pub enum APIError {
    JsonError(String),
    ValidationError(String),
    MissingHeader(String),
    InvalidHeader,
    Forbidden(String),
}

impl IntoResponse for APIError {
    fn into_response(self) -> Response {
        let (status, message) = match self {
            APIError::JsonError(msg) => (StatusCode::BAD_REQUEST, msg),
            APIError::ValidationError(msg) => (StatusCode::BAD_REQUEST, format!("Validation error: {}", msg)),
            APIError::MissingHeader(msg) => (StatusCode::BAD_REQUEST, format!("Missing header: {}", msg)),
            APIError::InvalidHeader => (StatusCode::BAD_REQUEST, "Invalid header encoding".to_string()),
            APIError::Forbidden(msg) => (StatusCode::FORBIDDEN, msg),
        };

        let body = Json(json!({
            "error": message
        }));

        (status, body).into_response()
    }
}

// ==========================================
// 5. The Handler
// ==========================================

// Note: ValidatedJson must be the LAST argument because it consumes the request body.
