/// This mocks the Context you would pass around in Pingora.
/// The key solution is storing the `tracing::Span` itself directly in your context.
/// This span represents the "root" or "request" lifespan.
#[derive(Clone)]
struct ProxyContext {
    pub req_id: String,
    /// We store the parent span here so we can refer to it 
    /// regardless of which thread or callback we are in.
    pub request_span: Span,
}

// -----------------------------------------------------------------------------
// 2. Trait Definition (The "Pingora" interface)
// -----------------------------------------------------------------------------

/// A trait simulating Pingora's async callback stages.
#[async_trait::async_trait]
trait ProxyCallbacks {
    async fn request_filter(&self, ctx: &mut ProxyContext) -> bool;
    async fn upstream_peer(&self, ctx: &mut ProxyContext) -> String;
    async fn logging(&self, ctx: &mut ProxyContext);
}

struct MyProxy;

#[async_trait::async_trait]
impl ProxyCallbacks for MyProxy {

    // STAGE 1
    async fn request_filter(&self, ctx: &mut ProxyContext) -> bool {
        // SOLUTION: Create a new span explicitly parented to the stored span.
        // Even though we are in a new async task/callback, we link back to ctx.request_span.
        let span = info_span!(parent: &ctx.request_span, "Stage 1 (Filter)");

        async move {
            info!("Filtering request...");
            tokio::time::sleep(Duration::from_millis(50)).await;
            info!("Filter passed.");
            true
        }
        .instrument(span) // Activates the span for this block
        .await
    }

    // STAGE 2
    async fn upstream_peer(&self, ctx: &mut ProxyContext) -> String {
        // SOLUTION: Repeat the pattern. This Span is a sibling of Stage 1,
        // but a child of the Request Span.
        let span = info_span!(parent: &ctx.request_span, "Stage 2 (Upstream Selection)");

        async move {
            info!("Selecting upstream...");
            tokio::time::sleep(Duration::from_millis(50)).await;
            let peer = "127.0.0.1:8080";
            info!(%peer, "Upstream selected");
            peer.to_string()
        }
        .instrument(span)
        .await
    }

    // STAGE 3 (Cleanup/Logging)
    async fn logging(&self, ctx: &mut ProxyContext) {
        // You can also just "enter" the parent scope if you don't want a sub-span,
        // but want the logs to belong to the parent Request.
        let _guard = ctx.request_span.enter();
        info!("Finalizing request log (direct child of Parent)");
    }
}

// -----------------------------------------------------------------------------
// 3. Runtime Simulation
// -----------------------------------------------------------------------------

#[tokio::main]
