/// Simulates the Pingora internal loop (the "Black Box")
async fn handle_request(proxy: MyProxy, id: &str) {
    // 1. Connection arrives, Framework creates the Root Span
    let root_span = info_span!("Request/Parent Span", http.req_id = %id);

    // 2. Framework initializes Context with that Span
    let mut ctx = ProxyContext {
        req_id: id.to_string(),
        request_span: root_span, // Store it!
    };

    // 3. Framework calls callbacks at arbitrary times/threads.
    // Note: We are NOT using .instrument() on these calls to simulate 
    // the "disconnected" nature of callback runtime environments.

    // Call Stage 1
    let _allowed = proxy.request_filter(&mut ctx).await;

