// We cannot use standard rand::ChaCha8Rng in a const context because 
// traits functions like RngCore::next_u64 are not const.
// 
// Instead, we implement a simple, robust PRNG (SplitMix64) manually within 
// a const function. This allows us to generate the array at compile time 
// with a fixed seed.

pub static ZOBRIST_SEEDS: [u64; ARRAY_SIZE] = generate_zobrist_seeds(4174800045971885562);

const fn generate_zobrist_seeds(seed: u64) -> [u64; ARRAY_SIZE] {
    let mut result = [0; ARRAY_SIZE];
    let mut s = seed;
    let mut i = 0;

    while i < ARRAY_SIZE {
        // Implementation of SplitMix64, a pseudo-random number generator 
        // that is simple, fast, and suitable for Zobrist hashing.
        // It uses wrapping arithmetic which is allowed in const contexts.
        s = s.wrapping_add(0x9e3779b97f4a7c15);
        let mut z = s;
        z = (z ^ (z >> 30)).wrapping_mul(0xbf58476d1ce4e5b9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94d049bb133111eb);
        result[i] = z ^ (z >> 31);

        i += 1;
    }

    result
}

