    println!("Array Size: {}", ZOBRIST_SEEDS.len());

    println!("\nFirst 5 values:");
    for i in 0..5 {
        println!("[{}] = {}", i, ZOBRIST_SEEDS[i]);
    }

    println!("\nLast 5 values:");
    for i in (ARRAY_SIZE - 5)..ARRAY_SIZE {
        println!("[{}] = {}", i, ZOBRIST_SEEDS[i]);
    }
}"
