//! No cycles.

// ---------------------------------------------------------
// Crate: al (Abstract Layer)
// ---------------------------------------------------------
pub mod al {
    use enum_dispatch::enum_dispatch;

    // By annotating the trait with an empty #[enum_dispatch], 
    // we allow downstream crates (like `bl`) to implement this trait 
    // for their enums automatically.
    #[enum_dispatch]
    pub trait Rest {
        fn get(&self, path: &str) -> String;
        fn post(&self, path: &str, body: &str) -> String;
        // Imagine 18 other methods here...
    }
}

// ---------------------------------------------------------
// Crate: il (Implementation Layer)
// Depends on: al
// ---------------------------------------------------------
