    use crate::al::Rest;

    // Struct 1
    pub struct Foo {
        pub api_key: String,
    }

    impl Rest for Foo {
        fn get(&self, path: &str) -> String {
            format!("[Foo-Ref: {}] GET {}", self.api_key, path)
        }

        fn post(&self, path: &str, body: &str) -> String {
            format!("[Foo-Ref: {}] POST {} with payload '{}'", self.api_key, path, body)
        }
    }

    // Struct 2
    pub struct Boo {
        pub id: u32,
    }

    impl Rest for Boo {
        fn get(&self, path: &str) -> String {
            format!("[Boo-Val: {}] GET {}", self.id, path)
        }

        fn post(&self, path: &str, body: &str) -> String {
            format!("[Boo-Val: {}] POST {} with payload '{}'", self.id, path, body)
        }
    }
}

// ---------------------------------------------------------
// Crate: bl (Business Layer)
// Depends on: al, il
// ---------------------------------------------------------
pub mod bl {
    use crate::al::Rest;
    use crate::il::{Foo, Boo};
    use enum_dispatch::enum_dispatch;

    // Here we construct the Enum that bridges implementations.
    // Since `Rest` in `al` is marked with `#[enum_dispatch]`, we can reference it here.
    // This generates the extensive match statements for all 20 methods automatically.
    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo,
        Boo,
    }

    pub fn run_system() {
        // Create concrete instances
        let f = Foo { api_key: "secret_123".into() };
