The following solution provides a ready-to-run Rust project. 

### Explanation of the Solution

To make this work on **stable Rust**, we face a specific limitation: the compiler cannot currently automatically infer that the opaque Future returned by an `async` block satisfies the `Send` requirement when that Future captures a reference argument (Higher-Ranked Trait Bounds).

To "nicely wrap" this, we use two components:
1.  **Refined Enum Definition**: We look for `FnOnce` instead of `Fn` (since tasks are usually one-off), and we expect a pinned, boxed future.
2.  **A Helper Macro**: Since we cannot eliminate the need for `Box::pin` in the types (due to the limitation mentioned above), we hide it using a simple macro. This allows you to write natural-looking async closures.

### Files

```json
{
  "Cargo.toml": "[package]
name = "async_thread_wrapper"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc;

// 1. The Context Data
pub struct Context(i32);

// 2. The Type Alias for our Job
// We use `FnOnce` because a task is usually consumed once.
// It takes a mutable reference to Context and returns a Pinned, Send-safe Future.
pub type AsyncJob = Box<dyn FnOnce(&mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> + Send>;

// 3. The Event Enum
pub enum InnerAsyncEvent {
    DoWithContext {
        block: AsyncJob,
    },
}

// 4. A Helper to construct the event and send it.
// This accepts any closure that matches the signature explicitly.
// Note: On stable Rust, we still explicitly require the return type to be Pin<Box<...>>
// because generics cannot yet infer 'Send' on opaque future types with borrowed args.
pub async fn send_job<F>(sender: &mpsc::Sender<InnerAsyncEvent>, f: F)
where
    F: FnOnce(&mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> + Send + 'static,
{
    let event = InnerAsyncEvent::DoWithContext {
        block: Box::new(f),
    };
    let _ = sender.send(event).await;
}

// 5. The "Nice Wrapper" (Macro)
// This macro hides the ugly `Box::pin(async move { ... })` syntax.
// It allows you to write: with_context_async!(sender, |ctx| { ctx.0 += 1; });
macro_rules! with_context_async {
    ($sender:expr, |$ctx:ident| $body:block) => {
        // We call the helper function defined above
        send_job($sender, move |$ctx: &mut Context| {
            // We perform the manual pinning here, hidden from the call site
            Box::pin(async move {
                $body
            })
        })
    };
    // Variant for expression bodies (no braces)
    ($sender:expr, |$ctx:ident| $body:expr) => {
        with_context_async!($sender, |$ctx| { $body; })
    };
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel(32);

    // Spawn the worker thread
    tokio::spawn(async move {
        let mut ctx = Context(0);
        println!("Worker: Started with Context(0)");

        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    // Execute the wrapper (the closure)
                    // This returns the Pinned Future, which we await.
                    block(&mut ctx).await;
                    println!("Worker: Context value is now {}", ctx.0);
                }
            }
        }
    });

    // --- Usage Example ---

    // 1. Sending a job using the nice macro wrapper
    // Note: We can move data into this block comfortably.
    let increment_amount = 5;

    with_context_async!(&tx, |c| {
        println!("Job 1: Incrementing by {}", increment_amount);
        c.0 += increment_amount;
        // Simulate async work
        tokio::time::sleep(std::time::Duration::from_millis(100)).await;
    }).await;

    // 2. Sending another job
    with_context_async!(&tx, |c| {
        println!("Job 2: Resetting");
        c.0 = 0;
    }).await;

    // Cleanup
    drop(tx);
    // Give the worker a moment to finish printing before main exits
    tokio::time::sleep(std::time::Duration::from_millis(200)).await;
}
"
}
```

