{
  "Cargo.toml": "[package]
name = "manual-poll-tokio"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1.36", features = ["full"] }
futures = "0.3"
",
  "main.rs": "use std::future::Future;
use std::pin::Box;
use std::task::{Context, Poll};
use std::time::Duration;
use futures::task::noop_waker;

/// This function demonstrates how to manually poll a future synchronously.
/// 
/// - `fut`: The future to evaluate.
/// 
/// Logic:
/// 1. We wrap the future in a `Pin<Box<_>>`. This is crucial because if it returns Pending,
///    we need to move it into a `tokio::spawn` closure. `Pin<Box<F>>` is `Unpin`, allowing this move.
/// 2. We create a `Context` with a `noop_waker`. If the future is Pending, it might register
///    this waker. Since it does nothing, no wake-up signal will occur from this specific poll.
///    However, this is safe because if it is Pending, we immediately spawn it, at which point
///    Tokio will poll it again with a legitimate waker, overwriting the no-op registration.
fn poll_or_spawn<F>(fut: F, name: &str)
where
    F: Future<Output = String> + Send + 'static,
{
    // 1. Pin the future on the heap so we can poll it and potentially move it later.
    let mut pinned_future = Box::pin(fut);

    // 2. Create a Context with a no-op waker.
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    println!("[Logic] Polling '{}'...", name);

    // 3. Poll manually
    match pinned_future.as_mut().poll(&mut cx) {
        Poll::Ready(val) => {
            // Case A: Future completed synchronously
            println!("[Sync]  '{}' is Ready! Value: \"{}\"", name, val);
        }
        Poll::Pending => {
            // Case B: Future is not ready
            println!("[Async] '{}' is Pending. Spawning a background task...", name);

            tokio::spawn(async move {
                // Continue awaiting the *same* pinned future in a new task
                let val = pinned_future.await;
                println!("[Task]  '{}' finished in background. Value: \"{}\"", name, val);
            });
        }
    }
}

#[tokio::main]
async fn main() {
    println!("--- Starting Application ---\n");

    // 1. Test with a future that is ready immediately
    let future_immediate = async {
        "Immediate Result".to_string()
    };
    poll_or_spawn(future_immediate, "JOB_A");

    println!("");

    // 2. Test with a future that takes time (yields pending)
    let future_delayed = async {
        // Sleep requires the tokio runtime to be active, which it is.
        tokio::time::sleep(Duration::from_secs(1)).await;
        "Delayed Result".to_string()
    };
    poll_or_spawn(future_delayed, "JOB_B");

    println!("\n--- Main function Sync logic finished ---");
    println!("--- Waiting for background tasks to prove they work ---");

    // We wait here purely to let the background spawned task finish printing for the demo.
    tokio::time::sleep(Duration::from_secs(2)).await;
}
"
}
