#[derive(Debug)]
enum FlusterError {
    FailToParseDate,
}

type FlusterResult<T> = Result<T, FlusterError>;

/// The specific fix is changing from `DateTime::parse_from_str` to 
/// `NaiveDateTime::parse_from_str`. 
/// 
/// `DateTime` expects a TimeZone offset (like +00:00 or Z) in the string. 
/// Since LanceDB is returning strings without offsets (e.g. "2025-08-02T17:35:41.409"), 
/// the parser throws "NotEnough" because it reached the end of the string 
/// while still looking for timezone data.
///
/// We parse as Naive (no timezone), then tell Chrono to treat it as UTC.
pub fn date_string_to_int(d: &str) -> FlusterResult<i64> {
    // %Y-%m-%dT%H:%M:%S matches the standard ISO parts.
    // %.f matches the fractional seconds if they exist, or handles it if they don't.
    let format = "%Y-%m-%dT%H:%M:%S%.f";

    let naive_date = NaiveDateTime::parse_from_str(d, format).map_err(|e| {
        println!("Date Error: {:?}", e);
        FlusterError::FailToParseDate
    })?;

    // Assume the database stored these as UTC.
    let date_time_utc = Utc.from_utc_datetime(&naive_date);

    println!("Parsed: {:?} -> Timestamp (ms): {}", date_time_utc, date_time_utc.timestamp_millis());

    // Returning milliseconds to preserve the precision seen in valid inputs
    Ok(date_time_utc.timestamp_millis())
}

