{
  "Cargo.toml": "[package]
name = "notion_struct_mapper"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"
",
  "main.rs": "use std::collections::HashMap;
use serde::{Serialize, Deserialize};

// ==========================================
// 1. Notion API Type Stubs
// these represent the JSON structure expected by Notion
// ==========================================

#[derive(Debug, Serialize, Deserialize, Clone)]
#[serde(rename_all = "snake_case", tag = "type")]
pub enum PropertyValue {
    Title { title: Vec<RichTextObject> },
    Url { url: String },
    MultiSelect { multi_select: Vec<SelectObject> },
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct RichTextObject {
    pub text: TextObject,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub plain_text: Option<String>,
    // Add other fields (annotations, etc.) as needed
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct TextObject {
    pub content: String,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct SelectObject {
    pub name: String,
}

// Helper constructors for cleaner code
impl RichTextObject {
    pub fn from_str(s: &str) -> Self {
        Self {
            text: TextObject { content: s.to_string() },
            plain_text: Some(s.to_string()),
        }
    }
}

impl SelectObject {
    pub fn from_str(s: &str) -> Self {
        Self { name: s.to_string() }
    }
}

// ==========================================
// 2. The Macro Solution
// ==========================================

/// This macro simulates a helper attribute. In a multi-crate setup,
/// this would be a procedural macro (#[derive]).
/// Here, we use macro_rules! to define the struct and implement the
/// conversion logic in one pass.
macro_rules! notion_object {
    (
        // Parse Struct Attributes (e.g., derive)
        $(#[$struct_attr:meta])*
        struct $struct_name:ident {
            $(
                // Parse our custom "attribute": #[notion(Type, "KeyName")]
                $(#[notion($notion_type:ident, $key_name:literal)])*
                pub $field_name:ident : $field_type:ty
            ),* $(,)?
        }
    ) => {
        // 1. Embody the Struct Definition
        $(#[$struct_attr])*
        struct $struct_name {
            $( pub $field_name : $field_type ),*
        }

        // 2. Implement the Conversion Logic
        impl $struct_name {
            pub fn to_notion_properties(&self) -> HashMap<String, PropertyValue> {
                let mut map = HashMap::new();

                $(
                    // We match which code block to generate based on the notion_type identifier
                    // passed in the attribute.
                    notion_object!(@expand_field, 
                        map, 
                        $key_name, 
                        self.$field_name, 
                        $($notion_type)* // Pass the type (Title, Url, etc)
                    );
                )*

                map
            }
        }
    };

    // -- Expansion Rules for specific Notion Types --

    // Expansion: Title (String -> PropertyValue::Title)
    (@expand_field, $map:ident, $key:literal, $val:expr, Title) => {
        $map.insert(
            $key.to_string(),
            PropertyValue::Title {
                title: vec![RichTextObject::from_str(&$val)]
            }
        );
    };

    // Expansion: Url (Option<String> -> PropertyValue::Url)
    // Only inserts if Some
    (@expand_field, $map:ident, $key:literal, $val:expr, Url) => {
        if let Some(ref u) = $val {
            $map.insert(
                $key.to_string(),
                PropertyValue::Url { url: u.clone() }
            );
        }
    };

    // Expansion: MultiSelect (Option<Vec<impl Display>> -> PropertyValue::MultiSelect)
    (@expand_field, $map:ident, $key:literal, $val:expr, MultiSelect) => {
        if let Some(ref items) = $val {
            $map.insert(
                $key.to_string(),
                PropertyValue::MultiSelect {
                    multi_select: items.iter()
                        .map(|item| SelectObject::from_str(&item.to_string()))
                        .collect()
                }
            );
        }
    };

    // Fallback/Error for unknown types (Optional safety)
    (@expand_field, $map:ident, $key:literal, $val:expr, $unknown:ident) => {
        compile_error!(concat!("Unknown notion type: ", stringify!($unknown)));
    };
}

// ==========================================
// 3. User Code
// ==========================================

// usage of our macro to define the struct and mapping simultaneously
notion_object! {
    #[derive(Serialize, Deserialize, Debug)]
    struct MyUnit {
        #[notion(Title, "Name")]
        pub name: String,

        #[notion(Url, "Icon url")]
        pub icon_url: Option<String>,

        #[notion(MultiSelect, "Roles")]
        pub categories: Option<Vec<String>>
    }
}

fn main() {
    // 1. Create the instance of the struct
    let unit = MyUnit {
        name: "Project Alpha".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec!["Admin".to_string(), "Editor".to_string()]),
    };

    println!("--- Original Struct ---");
    println!("{:?}", unit);

    // 2. Convert to Notion HashMap using the generated method
    let properties = unit.to_notion_properties();

    // 3. Serialize to map ensuring the JSON keys match Notion API
    println!("\n--- Notion API Payload (JSON) ---");
    println!(
        "{}", 
        serde_json::to_string_pretty(&properties).expect("Serialization failed")
    );
}"
}
