response:
To solve the issue where a cached `tokio_postgres::Client` becomes "Closed" and unrecoverable, you must handle the lifecycle of the connection more dynamically than a `OnceCell` allows.

The `tokio_postgres::Client` handle is essentially a lightweight reference (internally using `Arc`) to the request channel. It is cheap to clone. However, if the underlying connection task (spawned via `tokio::spawn`) terminates—due to a network glitch, timeout, or server restart—the `Client` enters a permanent `Closed` state.

**The Solution:**
1.  Use `Arc<tokio::sync::Mutex<Option<Client>>>` instead of `OnceCell`.
2.  Before returning the cached client, check `local_client.is_closed()`.
3.  If it is closed (or `None`), force a reconnection and update the Mutex.

This approach ensures that if the specific "cached" connection dies, your library automatically heals itself by reconnecting on the next request, rather than failing 40% of the time.

Here are the complete files.

```json
{
  "Cargo.toml": "[package]
name = "postgres_cache_handle"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
tokio-postgres = "0.7"
",
  "main.rs": "use std::sync::Arc;
use tokio::sync::Mutex;
use tokio_postgres::{Client, NoTls};

// --- Configuration Structures ---

#[derive(Debug, Clone)]
pub struct DbConfig {
    pub port: u16,
    pub name: String,
    pub user: String,
    pub postgres_password: String,
    pub db_password: String,
}

pub struct DbContainer {
    // We don't really need the container_name for the connection logic,
    // but keeping it to match your structure.
    _container_name: String,
    db_config: DbConfig,
    // The Fix: Use Mutex<Option> instead of OnceCell so we can
    // replace the client if the connection causes an error or closes.
    default_client: Arc<Mutex<Option<Client>>>,
}

impl DbContainer {
    pub fn new<N>(container_name: N, db_config: DbConfig) -> Self
    where
        N: Into<String>,
    {
        Self {
            _container_name: container_name.into(),
            db_config,
            default_client: Arc::new(Mutex::new(None)),
        }
    }

    /// Generates the connection string.
    fn make_conn_string(&self, db_name: Option<&str>) -> String {
        let mut conn_str = format!(
            "host=localhost port={} user={} password={}",
            self.db_config.port,
            self.db_config.user,
            self.db_config.postgres_password
        );

        if let Some(dbname) = db_name {
            conn_str.push_str(&format!(" dbname={dbname}"));
        }
        conn_str
    }

    /// Gets a client. 
    /// If `db_name` is provided, always opens a new fresh connection (not cached).
    /// If `db_name` is None (default 'postgres' db), it recycles the cached connection.
    async fn connect(&self, db_name: Option<&str>) -> Result<Client, tokio_postgres::Error> {
        // Case 1: Specific Database (New Connection every time)
        if let Some(name) = db_name {
            let (client, conn) = tokio_postgres::connect(&self.make_conn_string(Some(name)), NoTls).await?;

            tokio::spawn(async move {
                if let Err(e) = conn.await {
                    // This might happen when we drop the database, effectively killing this connection.
                    // It is expected behavior for temporary DB connections.
                    eprintln!("Connection to specific DB '{}' closed: {}", name, e);
                }
            });
            return Ok(client);
        }

        // Case 2: Default Database (Cached Connection)
        let mut guard = self.default_client.lock().await;

        // Check if we have a valid, open client
        if let Some(existing_client) = &*guard {
            if !existing_client.is_closed() {
                // Client is cheap to clone (it's just an Arc handle and a channel)
                return Ok(existing_client.clone());
            }
            println!("Cached client is closed. Reconnecting...");
        }

        // Establish new default connection
        let (client, conn) = tokio_postgres::connect(&self.make_conn_string(None), NoTls).await?;

        tokio::spawn(async move {
            if let Err(e) = conn.await {
                eprintln!("Default connection error: {}", e);
            }
        });

        // Cache it
        *guard = Some(client.clone());

        Ok(client)
    }

    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.connect(None).await?;

        // Check if DB exists to prevent errors during repeated local tests
        let exists: bool = client
            .query_one("SELECT EXISTS(SELECT 1 FROM pg_database WHERE datname = $1)", &[&name])
            .await?
            .get(0);

        if !exists {
            client
                .execute(&format!("CREATE DATABASE \"{}\"", name), &[])
                .await?;
        }

        // Connect to the new DB and run schema
        let client_specific = self.connect(Some(name)).await?;
        client_specific.batch_execute("CREATE TABLE IF NOT EXISTS test (id SERIAL PRIMARY KEY);").await
    }

    pub async fn drop_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.connect(None).await?;

        // Terminate existing connections to the target DB
        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{}' AND pid <> pg_backend_pid();
            ", name
        );

        client.execute(&terminate_sql, &[]).await?;
        client.execute(&format!("DROP DATABASE IF EXISTS \"{}\"", name), &[]).await?;
        Ok(())
    }
}

// --- Main meant for 'cargo run' to test the fix ---

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Setup configuration (Expects a running Postgres on localhost:5432)
    // Docker: docker run --name pg -e POSTGRES_PASSWORD=password -p 5432:5432 -d postgres
    let config = DbConfig {
        port: 5432,
        name: "postgres".to_string(),
        user: "postgres".to_string(),
        postgres_password: "password".to_string(),
        db_password: "ignored_here".to_string(),
    };

    let container = DbContainer::new("my_test_container", config);

    println!("Starting stress test of cached connection...");

    // We loop to prove the client is cached and reused, 
    // and if it breaks, it self-heals.
    for i in 0..5 {
        let db_name = format!("test_db_{}", i);

        println!("[{i}] Creating {}", db_name);
        if let Err(e) = container.create_database(&db_name).await {
            eprintln!("Failed to create: {}. Make sure Postgres is running on localhost:5432 with password='password'", e);
            return Ok(());
        }

        // Simulate doing some work
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

        println!("[{i}] Dropping {}", db_name);
        container.drop_database(&db_name).await?;
    }

    println!("Success! Used cached client without 'Closed' errors.");
    Ok(())
}
"
}
```

