The following solution implements a highly maintainable pattern using a **Trait** to standardize the UI calls for primitives, and a **Macro** to automatically generate the `downcast` checks for the Type itself, `Vec<Type>`, and `Option<Type>` simultaneously.

This solves your problem of duplicating code: you simply add a type (e.g., `i32`) to the macro list once, and it automatically handles `i32`, `Vec<i32>`, and `Option<i32>`.

### Files

```json
{
  "Cargo.toml": "[package]
name = "rust_downcast_gui"
version = "0.1.0"
edition = "2021"

[dependencies]
eframe = "0.29"  # Egui framework wrapper
",
  "main.rs": "use std::any::Any;
use eframe::egui;
use eframe::egui::{Ui, Color32, RichText};

// ----------------------------------------------------------------------------
// 1. The Trait: Standardize how single items are drawn
// ----------------------------------------------------------------------------

/// Trait implemented by any type that can be drawn in the property window.
/// This replaces the explicit string_property, i_property, etc. calls with a uniform interface.
pub trait PropertyEditable: 'static + Default + Sized + Send + Sync {
    fn draw(&mut self, ui: &mut Ui, title: &str, interactable: bool);
}

// Implementations for Primitives

impl PropertyEditable for String {
    fn draw(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.horizontal(|ui| {
            ui.label(title);
            ui.add_enabled(interactable, egui::TextEdit::singleline(self));
        });
    }
}

impl PropertyEditable for i32 {
    fn draw(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.horizontal(|ui| {
            ui.label(title);
            ui.add_enabled(interactable, egui::DragValue::new(self));
        });
    }
}

impl PropertyEditable for f32 {
    fn draw(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.horizontal(|ui| {
            ui.label(title);
            ui.add_enabled(interactable, egui::DragValue::new(self).speed(0.1));
        });
    }
}

impl PropertyEditable for bool {
    fn draw(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.horizontal(|ui| {
            ui.label(title);
            ui.add_enabled(interactable, egui::Checkbox::new(self, ""));
        });
    }
}

// Example of a custom struct
#[derive(Default, Debug, Clone)]
pub struct MyCustomData {
    pub name: String,
    pub value: i32,
}

impl PropertyEditable for MyCustomData {
    fn draw(&mut self, ui: &mut Ui, title: &str, interactable: bool) {
        ui.collapsing(title, |ui| {
            // Recursive usage is simple now because the fields are primitives
            self.name.draw(ui, "Name", interactable);
            self.value.draw(ui, "Value", interactable);
        });
    }
}

// ----------------------------------------------------------------------------
// 2. The Macro: The magic that removes duplication
// ----------------------------------------------------------------------------

/// This macro generates the if-let-downcast chain.
/// For every type T passed in the list, it checks for:
/// 1. T
/// 2. Vec<T>
/// 3. Option<T>
macro_rules! generate_downcast_checks {
    // $val: the &mut dyn Any
    // $ui, $title, $inter: arguments passed through
    // [ $($Type:ty),* ]: A list of types comma separated
    ($val:expr, $ui:expr, $title:expr, $inter:expr, [ $($Type:ty),* ]) => {
        $(
            // 1. Check if it is the Type itself (e.g., i32)
            if let Some(v) = $val.downcast_mut::<$Type>() {
                v.draw($ui, $title, $inter);
                return;
            }

            // 2. Check if it is a Vec<Type> (e.g., Vec<i32>)
            if let Some(v) = $val.downcast_mut::<Vec<$Type>>() {
                list_property($ui, $title, v, $inter);
                return;
            }

            // 3. Check if it is an Option<Type> (e.g., Option<i32>)
            if let Some(v) = $val.downcast_mut::<Option<$Type>>() {
                option_property($ui, $title, v, $inter);
                return;
            }
        )*
    };
}

// ----------------------------------------------------------------------------
// 3. The Generics: List and Option Handlers
// ----------------------------------------------------------------------------

pub fn list_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Vec<T>, interactable: bool)
where
    T: PropertyEditable, // We require the item to be editable via our trait
{
    ui.collapsing(format!("{} (List)", title), |ui| {
        ui.horizontal(|ui| {
             if ui.add_enabled(interactable, egui::Button::new("➕ Add")).clicked() {
                 value_mut.push(T::default());
             }
             ui.label(format!("Count: {}", value_mut.len()));
        });

        let mut remove_idx = None;
        for (i, item) in value_mut.iter_mut().enumerate() {
            ui.horizontal(|ui| {
                // Recursion: logic is inside T::draw()
                item.draw(ui, &format!("Item {}", i), interactable);

                if interactable && ui.button("❌").clicked() {
                    remove_idx = Some(i);
                }
            });
        }

        if let Some(i) = remove_idx {
            value_mut.remove(i);
        }
    });
}

pub fn option_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Option<T>, interactable: bool)
where
    T: PropertyEditable,
{
    ui.horizontal(|ui| {
        ui.label(format!("{} (Opt)", title));

        let is_some = value_mut.is_some();
