// Change this to the specific website you want to allow
const ALLOWED_ORIGIN: &str = "http://127.0.0.1:3000";

#[tokio::main]
async fn main() {
    // Build our application with a route
    let app = Router::new()
        // 1. A public route to serve a test HTML page
        .route("/", get(index))
        // 2. The WebSocket route protected by our custom middleware
        .route("/ws", get(ws_handler))
        // We apply the middleware via route_layer so it runs before the handler
        .route_layer(middleware::from_fn(check_origin));

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    println!("Listening on {}\n", addr);
    println!("Test instructions:");
    println!("1. Open {} in your browser (Allowed Origin).", ALLOWED_ORIGIN);
    println!("2. Connection should succeed.");
    println!("3. Try connecting via a terminal: `curl -i -N -H \"Connection: Upgrade\" -H \"Upgrade: websocket\" -H \"Origin: https://evil.com\" {}/ws`", ALLOWED_ORIGIN);
    println!("4. Connection should be 403 Forbidden.");

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

/// Middleware to check the "Origin" header before upgrading to WebSocket
async fn check_origin(req: Request, next: Next) -> Result<Response, StatusCode> {
    // Extract the origin header
    let origin = req.headers()
        .get(header::ORIGIN)
        .and_then(|value| value.to_str().ok());

    match origin {
        Some(o) if o == ALLOWED_ORIGIN => {
            println!("Allowed connection from origin: {}", o);
            // Continue to the next handler (the websocket upgrade)
            Ok(next.run(req).await)
        }
        Some(o) => {
            println!("Blocked connection from invalid origin: {}", o);
            Err(StatusCode::FORBIDDEN)
        }
        None => {
            println!("Blocked connection with missing Origin header");
            Err(StatusCode::FORBIDDEN)
        }
    }
}

/// The actual WebSocket handler
async fn ws_handler(ws: WebSocketUpgrade) -> impl IntoResponse {
    ws.on_upgrade(handle_socket)
}

/// Simple echo socket logic
async fn handle_socket(mut socket: WebSocket) {
    while let Some(msg) = socket.recv().await {
        if let Ok(msg) = msg {
            if let Message::Text(text) = msg {
                if socket.send(Message::Text(format!("Echo: {}", text))).await.is_err() {
                    break;
                }
            }
        } else {
            break;
        }
    }
}

