    pub fn new(process_name: &str) -> Self {
        let formatter = Formatter3164 {
            facility: Facility::LOG_USER,
            hostname: None,
            process: process_name.into(),
            pid: std::process::id() as i32,
        };

        // Connect and unwrap here, or return Result in a real app
        let logger = syslog::unix(formatter).expect("Could not connect to syslog");

        ApiLogger { inner: logger }
    }

    /// The centralized function that eliminates repeated calls to .expect()
    /// It takes a mutable reference (&mut self) because writing to the socket requires mutation.
    pub fn log(&mut self, level: Severity, message: &str) {
        // We handle the error centrally here.
        // In C++, you might throw or ignore; in Rust, we explicitly handle the Result.
        if let Err(e) = self.inner.send(level, message) {
            eprintln!("FAILED TO LOG: {}", e);
        }
