use serde::Deserialize;
use std::sync::Arc;
use tokio::sync::mpsc;

// 1. Define the struct with borrowed content.
// This struct cannot exist on its own without the data it borrows from being alive.
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

// 2. Define a Self-Referencing entity.
// We use the `ouroboros` crate to create a struct that holds BOTH the raw JSON string (owner)
// AND the deserialized struct (borrower) in a single memory block.
// This creates a type that satisfies 'static, making it sendable across tokio tasks.
#[self_referencing]
struct JsonPackage {
    // The owner of the data
    source: String,

    // The borrower (dependent on `source`)
    #[borrows(source)]
    #[covariant]
    parsed: MyData<'this>,
}

// A helper type to pass errors cleanly
type ProcessResult = Result<(), Box<dyn std::error::Error + Send + Sync>>;

#[tokio::main]
async fn main() -> ProcessResult {
    // Create a generic channel to simulate incoming TCP stream
    let (tx, mut rx) = mpsc::channel::<String>(32);

    // Simulate a TCP producer task
    tokio::spawn(async move {
        let payloads = vec![
            r#"{ "data": "hello", "more_data": "world" }"#,
            r#"{ "data": "foo", "more_data": "bar" }"#,
            r#"{ "data": "tokio", "more_data": "spawn" }"#,
        ];

        for p in payloads {
            // Send raw strings (simulating reading from socket)
            let _ = tx.send(p.to_string()).await;
        }
    });

    // Consumer loop
    while let Some(raw_json) = rx.recv().await {
        // 3. Construct the self-referencing package.
        // We move the `raw_json` String into the package, then borrow it to parse.
        let package_result = JsonPackage::try_new(
            raw_json,
            |source_ref| serde_json::from_str::<MyData>(source_ref),
        );

        match package_result {
            Ok(package) => {
