/// A simple Ray vs OBB (Oriented Bounding Box) intersection test.
/// Returns (Hit World Position, Hit World Normal)
fn ray_cube_intersection(ray: Ray, box_tf: &Transform) -> Option<(Vec3, Vec3)> {
    let box_half_size = Vec3::splat(0.5);

    // 1. Transform Ray to Box Local Space
    // We inverse the box transform. For rotation, we multiply the inverse quat.
    let inv_rot = box_tf.rotation.inverse();
    let local_ray_origin = inv_rot * (ray.origin - box_tf.translation);
    let local_ray_dir = inv_rot * ray.direction;

    // 2. Slab Method Intersection (AABB in local space)
    // t_min and t_max track the entry and exit points along the ray
    let mut t_min = 0.0_f32;
    let mut t_max = 1000.0_f32;
    let mut outcome_normal = Vec3::ZERO;

    // Check X slabs
    if !intersect_slab(local_ray_origin.x, local_ray_dir.x, box_half_size.x, &mut t_min, &mut t_max, &mut outcome_normal, Vec3::X) {
        return None;
    }
    // Check Y slabs
    if !intersect_slab(local_ray_origin.y, local_ray_dir.y, box_half_size.y, &mut t_min, &mut t_max, &mut outcome_normal, Vec3::Y) {
        return None;
    }
    // Check Z slabs
    if !intersect_slab(local_ray_origin.z, local_ray_dir.z, box_half_size.z, &mut t_min, &mut t_max, &mut outcome_normal, Vec3::Z) {
        return None;
    }

    if t_min < t_max && t_max > 0.0 {
        let dist = t_min;
        let hit_pos_world = ray.origin + ray.direction * dist;

        // The calculated normal is in Local Space (e.g., 0,0,1).
        // Rotate it back to World Space to match what a Physics engine would return.
        let hit_normal_world = box_tf.rotation * outcome_normal;

        return Some((hit_pos_world, hit_normal_world));
    }

    None
}

fn intersect_slab(
    start: f32, 
    dir: f32, 
    limit: f32, 
    t_min: &mut f32, 
    t_max: &mut f32, 
    out_normal: &mut Vec3, 
    axis_vec: Vec3
) -> bool {
    let inverse_dir = 1.0 / dir;
    let mut t0 = (-limit - start) * inverse_dir;
    let mut t1 = (limit - start) * inverse_dir;
    let mut normal_sign = -1.0;

    if t0 > t1 {
        std::mem::swap(&mut t0, &mut t1);
        normal_sign = 1.0;
    }

    if t0 > *t_min {
        *t_min = t0;
        // If we entered a new slab, update the normal
        *out_normal = axis_vec * normal_sign;
    }
    if t1 < *t_max {
        *t_max = t1;
    }

    *t_min <= *t_max
}
