// To fix this, we need a trait that uses a lifetime parameter regarding the 
// input to determine the specific Output Future type. This allows us to use 
// Higher-Rank Trait Bounds (HRTB) via `for<'a>`.

trait AsyncTestFn<'a> {
    // The return type depends on the lifetime 'a
    type Fut: Future<Output = ()> + 'a;

    // The function signature connects the input lifetime to the output future
    fn call(&self, arg: &'a mut String) -> Self::Fut;
}

// We implement this trait for any function F that matches the pattern.
impl<'a, F, Fut> AsyncTestFn<'a> for F
where
    F: Fn(&'a mut String) -> Fut,
    Fut: Future<Output = ()> + 'a,
{
    type Fut = Fut;
    fn call(&self, arg: &'a mut String) -> Self::Fut {
        self(arg)
    }
}

// Harness now accepts F, provided F implements AsyncTestFn for *any* lifetime.
async fn harness<F>(test: F)
where
    F: for<'a> AsyncTestFn<'a>,
{
    let mut string = String::new();

    // harness setup
    string.push_str("pre-amble\n");

    // We call the trait method instead of the function directly
    test.call(&mut string).await;

    // harness teardown
    string.push_str("post-amble\n");
    println!("new string is:\n{string}");
}

